Okay, you are right. Displaying None units using the template makes no sense. Below you can find the draft of the function with the template section more developed (but without documentation):

```python
def format_label(quantity, unit=None, template=None, convention="divide"):

    DEFAULT_CONVENTION_LIST=[
        "divide",
        "parentheses",
        "brackets"
    ]
    
    if template is None:
        if unit is None:
            label = f"{quantity}"
        else:
            if convention not in DEFAULT_CONVENTION_LIST:
                raise NameError(f"Specified convention is not known.")
            else:
                if convention == "divide":
                    unit_form = f"\ ({unit})"

                elif convention == "parentheses":
                    unit_form = f"({unit})"

                elif convention == "brackets":
                    unit_form = f"[{unit}]"
                
                label = f"{quantity} {unit_form}"

    else:
        if "{quantity}" not in template and "{unit}" not in template:
            raise NameError("Template does not contain neither " +\
                            "{quantity} nor {unit}. Specify at least one.")
        else:
            if "{quantity}" not in template:
                log.warning("Quantity attribute is not in the template, "+\
                            "if required, add {quantity} to the template.")
                
                if unit is None:
                    label = ""  
                else:
                    label = template.format(
                        unit=unit
                    )                
                
            elif "{unit}" not in template:
                log.warning("Unit attribute is not in the template, "+\
                            "if required, add {unit} to the template.")     
        
                label = template.format(
                    quantity=quantity,
                )
            
            else:
                label = template.format(
                    quantity=quantity,
                    unit=unit
                )                  
    return label
